with open(file_path, 'r', encoding='utf-8') as f:
    content = f.read()

# Extract the array content
match = re.search(r'export const TAROT_CARDS: TarotCardData\[\] = \[(.*)\];', content, re.DOTALL)
if not match:
    print("Could not find TAROT_CARDS array")
    exit(1)

cards_text = match.group(1)

