# This is tricky because the objects contain nested braces in strings
# But since it's a standard format, we can try splitting by "  },"
cards = re.split(r'\n  \},', cards_text)
# Clean up and add the closing brace back to each except the last one (if empty)
cards = [c.strip() + '\n  }' for c in cards if c.strip()]

