# Construct the new cards text
new_cards_list = []
for i in range(len(cards)):
    if i in new_cards:
        # Convert dict to JS object string
        c = new_cards[i]
        obj_str = "  {\n"
        for key, value in c.items():
            if isinstance(value, list):
                obj_str += f'    "{key}": {json.dumps(value, ensure_ascii=False)},\n'
            else:
                obj_str += f'    "{key}": "{value}",\n'
        obj_str = obj_str.rstrip(',\n') + "\n  }"
        new_cards_list.append(obj_str)
    else:
        new_cards_list.append(cards[i])

new_cards_text = ',\n'.join(new_cards_list)

# Put back into the template
new_content = re.sub(r'export const TAROT_CARDS: TarotCardData\[\] = \[.*\];', 
                     f'export const TAROT_CARDS: TarotCardData[] = [\n{new_cards_text}\n];', 
                     content, flags=re.DOTALL)

with open(file_path, 'w', encoding='utf-8') as f:
    f.write(new_content)

